func TestWatchOnceEmitsNDJSON(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)
	db, err := store.Open(filepath.Join(home, ".local", "share", "superhuman-pp-cli", "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	if err := db.SaveHistoryState(t.Context(), "user@example.com", "100", time.Now(), time.Now()); err != nil {
		t.Fatalf("save history: %v", err)
	}
	db.Close()

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write([]byte(`{
			"history": [
				{"id":"101","messagesAdded":[{"message":{"id":"m1","threadId":"t1","labelIds":["INBOX"],"historyId":"101"}}]},
				{"id":"102","labelsRemoved":[{"message":{"id":"m2","threadId":"t2"},"labelIds":["INBOX"]}]}
			],
			"historyId": "103"
		}`))
	}))
	defer srv.Close()
	orig := gmail.BaseURL
	gmail.BaseURL = srv.URL
	t.Cleanup(func() { gmail.BaseURL = orig })
	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")

	stdout, _, err := executeCmd(t, "--config", configPath, "watch", "--once")
	if err != nil {
		t.Fatalf("watch --once: %v", err)
	}
	if !strings.Contains(stdout, `"event":"message_added"`) || !strings.Contains(stdout, `"event":"thread_archived"`) {
		t.Fatalf("watch output missing events: %s", stdout)
	}
}

func TestWatchFilterAndIntervalValidation(t *testing.T) {
	if !watchEventMatchesFilter([]string{"INBOX"}, "label:INBOX") {
		t.Fatalf("label filter should match")
	}
	if watchEventMatchesFilter([]string{"SENT"}, "label:INBOX") {
		t.Fatalf("label filter should not match")
	}
	configPath, _ := withConfigPath(t)
	_, _, err := executeCmd(t, "--config", configPath, "watch", "--interval", "0")
	if err == nil {
		t.Fatalf("expected interval validation error")
	}
}
